+                i32.const 96
+                i32.const 128
+                i32.store
+                i32.const 100
+                i32.const 4
+                i32.store
+                i32.const -100
+                i32.const 64
+                i32.const 0
+                i32.const 0
+                call $openat
+                local.tee $fd
+                i32.const 96
+                i32.const 1
+                i32.const 104
+                call $fd_read
+                drop
+                local.get $fd
+                call $fd_close
+                drop
+                i32.const 128
+                i32.load)
+              (func (export "bytes_read") (result i32)
+                i32.const 104
+                i32.load)
